class BankAccount:
    def __init__(self, owner, balance=0):
        self.owner = owner
        self.balance = balance

    def deposit(self, amount):
        self.balance += amount

acc = BankAccount("Alice", 100)
acc.deposit(50)
print(acc.balance)

def withdraw(self, amount):
    if amount > self.__balance:
        raise ValueError("Not enough funds")
    self.__balance -= amount

class Temperature:
    def __init__(self, c):
        self.__c = c

    @property
    def celsius(self):
        return self.__c

    @celsius.setter
    def celsius(self, value):
        if value < -273.15:
            raise ValueError("Below absolute zero!")
        self.__c = value

t = Temperature(25)
print(t.celsius)
t.celsius = 100
print(t.celsius)
